transform_js:
const data = [];
// 画面上のランダムな座標 [x, y] を生成して割り当てる
// X軸・Y軸は適当なダミー範囲 (0〜1000) とする
rawData.rows.forEach(r => {
  const x = Math.random() * 800 + 100; // 100~900
  const y = Math.random() * 800 + 100; // 100~900
  data.push([x, y, r.weight, r.word]);
});
// weightの降順でソート（大きい文字が上に描画されるように）
data.sort((a, b) => b[2] - a[2]);
transformedData = data;

echarts_js:
option = {
  title: {
    text: 'Pseudo Word Cloud via Custom Series',
    left: 'center',
    top: 20
  },
  tooltip: {
    formatter: function (info) {
      return info.value[3] + ': ' + info.value[2];
    }
  },
  // ダミーの座標軸（非表示）
  xAxis: { type: 'value', min: 0, max: 1000, show: false },
  yAxis: { type: 'value', min: 0, max: 1000, show: false },
  series: [
    {
      type: 'custom',
      // カスタムレンダリングロジック
      renderItem: function (params, api) {
        // 中心座標
        const pos = api.coord([api.value(0), api.value(1)]);
        const size = api.size([api.value(2), 0])[0]; // X軸上でのスケール値を利用
        // 文字の大きさを調整（最小10, 最大80くらいに正規化）
        const maxWeight = 100;
        const fontSize = Math.max(12, (api.value(2) / maxWeight) * 80);

        // ランダムな色
        const colors = ['#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de', '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc'];
        const color = colors[params.dataIndex % colors.length];

        return {
          type: 'text',
          x: pos[0],
          y: pos[1],
          style: {
            text: api.value(3),
            font: 'bold ' + fontSize + 'px sans-serif',
            fill: color,
            textAlign: 'center',
            textVerticalAlign: 'middle',
            opacity: 0.8,
            shadowBlur: 2,
            shadowColor: '#fff'
          }
        };
      },
      data: transformedData
    }
  ]
};
